const i = $input.first().json || {};
const h = i.headers || {};
let body = {};
if (i.body && typeof i.body === 'object') {
  body = i.body;
} else if (typeof i.body === 'string') {
  try {
    body = JSON.parse(i.body);
  } catch (_) {
    body = {};
  }
}
const draft = body.draft && typeof body.draft === 'object' ? body.draft : {};
const barberia = draft.barberia && typeof draft.barberia === 'object' ? draft.barberia : {};
const accesos = draft.accesos && typeof draft.accesos === 'object' ? draft.accesos : {};
const admin = accesos.admin && typeof accesos.admin === 'object' ? accesos.admin : {};
const accessBarbers = Array.isArray(accesos.barberos) ? accesos.barberos : [];
const cookieHeader = (h.cookie ?? h.Cookie ?? '').toString();
const m = cookieHeader.match(/(?:^|;\s*)ba_session=([^;]+)/);
const session_token = m ? m[1] : '';
const clean = (v) => (v ?? '').toString().trim();
const toNumber = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : 0;
};
const normalizeServicios = (rows) => Array.isArray(rows) ? rows
  .map((item) => ({
    nombre: clean(item?.nombre || item?.name),
    duracion_min: Math.max(1, Number(item?.duracion_min || item?.duration_min || 30)),
    precio: Math.max(0, Number(item?.precio || item?.price || 0)),
    imagen_url: clean(item?.imagen_url || item?.image_url || item?.foto_url || item?.foto)
  }))
  .filter((item) => item.nombre) : [];
const findAccessForBarber = (item, index) => {
  const id = toNumber(item?.id || item?.barbero_id);
  const nombre = clean(item?.nombre || item?.name).toLowerCase();
  const byIndex = accessBarbers[index] && typeof accessBarbers[index] === 'object' ? accessBarbers[index] : null;
  if (byIndex && (!id || toNumber(byIndex.id || byIndex.barbero_id) === id)) return byIndex;
  return accessBarbers.find((access) => {
    const accessId = toNumber(access?.id || access?.barbero_id);
    const accessName = clean(access?.nombre || access?.name).toLowerCase();
    return (id && accessId === id) || (!id && nombre && accessName === nombre);
  }) || {};
};
const normalizeBarberos = (rows) => Array.isArray(rows) ? rows
  .map((item, index) => {
    const id = toNumber(item?.id || item?.barbero_id);
    const access = findAccessForBarber(item, index);
    const payload = {
      id,
      usuario_id: toNumber(item?.usuario_id || item?.user_id),
      nombre: clean(item?.nombre || item?.name),
      foto_url: clean(item?.foto_url || item?.foto || item?.avatar_url || item?.image_url),
      activo: item?.activo === undefined ? true : Boolean(item.activo)
    };
    if (!id) {
      payload.email = clean(access?.email || item?.email).toLowerCase();
      payload.password = clean(access?.password || item?.password);
    }
    return payload;
  })
  .filter((item) => item.nombre) : [];
const dayToIndex = { domingo: 0, lunes: 1, martes: 2, miercoles: 3, jueves: 4, viernes: 5, sabado: 6 };
const normalizeHorarios = (rows) => Array.isArray(rows) ? rows
  .map((item) => {
    const dia = clean(item?.dia || '').toLowerCase();
    const dia_semana = Number.isInteger(item?.dia_semana) ? Number(item.dia_semana) : dayToIndex[dia];
    return {
      dia_semana,
      activo: Boolean(item?.activo),
      hora_abre: clean(item?.hora_abre) || '09:00',
      hora_cierra: clean(item?.hora_cierra) || '18:00'
    };
  })
  .filter((item) => Number.isInteger(item.dia_semana) && item.dia_semana >= 0 && item.dia_semana <= 6) : [];

return [{
  json: {
    session_token,
    request: {
      mode: clean(body.mode || 'edit'),
      barberia_id: toNumber(body.barberia_id || barberia.barberia_id || barberia.id || barberia.id_barberia),
      slug: clean(body.slug || barberia.slug),
      barberia: {
        nombre: clean(barberia.nombre || body.nombre),
        slug: clean(body.slug || barberia.slug),
        telefono: clean(barberia.telefono || body.telefono),
        direccion: clean(barberia.direccion || body.direccion),
        ciudad: clean(barberia.ciudad || body.ciudad),
        politicas: clean(barberia.politicas || body.politicas),
        slot_min: toNumber(barberia.slot_min || body.slot_min || 15)
      },
      servicios: normalizeServicios(draft.servicios || body.servicios),
      barberos: normalizeBarberos(draft.barberos || body.barberos),
      horarios: normalizeHorarios(draft.horarios || body.horarios),
      admin: {
        nombre: clean(admin.nombre),
        email: clean(admin.email).toLowerCase(),
        password: clean(admin.password)
      }
    }
  }
}];

const jwt = $input.first().json || {};
const request = $('Code - parse request').first().json.request || {};
const auth_ok = !jwt.error && !!jwt.payload?.user_id;
const user_id = auth_ok ? Number(jwt.payload.user_id) : 0;
const asJson = (value, fallback) => JSON.stringify(value ?? fallback);
return [{
  json: {
    params: [
      user_id,
      auth_ok,
      Number(request.barberia_id || 0),
      request.slug || null,
      request.mode || 'edit',
      asJson(request.barberia, {}),
      asJson(request.servicios, []),
      asJson(request.barberos, []),
      asJson(request.horarios, []),
      asJson(request.admin, {})
    ]
  }
}];

const row = $input.first().json || {};
return [{
  json: {
    status_code: Number(row.status_code || (row.ok ? 200 : 400)),
    body: {
      ok: !!row.ok,
      code: row.code || (row.ok ? 'configuracion_actualizada' : 'datos_invalidos'),
      message: row.message || '',
      data: row.data || null
    }
  }
}];
